#![allow(non_camel_case_types)]
#![allow(private_interfaces)]
#![deny(warnings)]

use std::path::PathBuf;
use std::process::ExitCode;

use rbtd::rbtdrc_crucible::{
    rbtdrc_lookup_fixture, rbtdrc_set_context, rbtdrc_take_context, RBTDRC_FIXTURES,
